CREATE TABLE IF NOT EXISTS tommy_boosting_players (id INT AUTO_INCREMENT PRIMARY KEY,identifier VARCHAR(64) UNIQUE NOT NULL,name VARCHAR(100),profile_name VARCHAR(24),profile_image VARCHAR(255),xp INT DEFAULT 0,level INT DEFAULT 1,crypto INT DEFAULT 0,completed_contracts INT DEFAULT 0,failed_contracts INT DEFAULT 0,total_cash_earned INT DEFAULT 0,total_crypto_earned INT DEFAULT 0,total_xp_earned INT DEFAULT 0,last_active TIMESTAMP NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tommy_boosting_contracts (id INT AUTO_INCREMENT PRIMARY KEY,contract_id VARCHAR(64) UNIQUE NOT NULL,owner_identifier VARCHAR(64),assigned_identifier VARCHAR(64),class VARCHAR(5),vehicle_model VARCHAR(60),plate VARCHAR(20),search_zone VARCHAR(100),dropoff VARCHAR(100),cash_reward INT,crypto_reward INT,xp_reward INT,status VARCHAR(30),requires_hacking TINYINT DEFAULT 0,has_tracker TINYINT DEFAULT 0,tracker_removed TINYINT DEFAULT 0,has_guards TINYINT DEFAULT 0,is_locked TINYINT DEFAULT 0,requires_partner TINYINT DEFAULT 0,vin_scratched TINYINT DEFAULT 0,failure_reason VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,accepted_at TIMESTAMP NULL,completed_at TIMESTAMP NULL,expires_at TIMESTAMP NULL);
CREATE TABLE IF NOT EXISTS tommy_boosting_history (id INT AUTO_INCREMENT PRIMARY KEY,contract_id VARCHAR(64),identifier VARCHAR(64),class VARCHAR(5),vehicle_model VARCHAR(60),plate VARCHAR(20),status VARCHAR(30),cash_reward INT,crypto_reward INT,xp_reward INT,failure_reason VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tommy_boosting_store_purchases (id INT AUTO_INCREMENT PRIMARY KEY,identifier VARCHAR(64),item VARCHAR(100),label VARCHAR(100),price INT,quantity INT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tommy_boosting_transfers (id INT AUTO_INCREMENT PRIMARY KEY,contract_id VARCHAR(64),from_identifier VARCHAR(64),to_identifier VARCHAR(64),price INT DEFAULT 0,currency VARCHAR(20),note VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tommy_boosting_admin_logs (id INT AUTO_INCREMENT PRIMARY KEY,admin_identifier VARCHAR(64),admin_name VARCHAR(100),action VARCHAR(100),target_identifier VARCHAR(64),details TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
